const GEN_SCRIPT = `import csv, shutil, math, datetime, zipfile, json, sys, os
from collections import defaultdict
from openpyxl import load_workbook, Workbook
from openpyxl.styles import Font, PatternFill, Alignment, Side, Border

CSV_PATH = sys.argv[1] if len(sys.argv) > 1 else '/mnt/user-data/uploads/ORDER_ITEMS_MASTER_SHEET.csv'
OUT_DIR  = sys.argv[2] if len(sys.argv) > 2 else '/tmp/gen_out'
DATE_STR = sys.argv[3] if len(sys.argv) > 3 else datetime.date.today().strftime('%d-%m-%Y')
GEN_TYPE = sys.argv[4] if len(sys.argv) > 4 else 'all'
TPL_DIR  = sys.argv[5] if len(sys.argv) > 5 else '/mnt/user-data/uploads'

os.makedirs(OUT_DIR, exist_ok=True)

with open(CSV_PATH, newline='', encoding='utf-8-sig') as f:
    ALL = list(csv.DictReader(f))
rows = [r for r in ALL if r.get('SKU','') != 'FREIGHT']
# Always derive Product from SKU — CSV Product field is unreliable (Ordermentum exports 'JUICE' or 'TEA' for 1L SKUs)
TEA_SKUS = {'LTEA350','PTEA350','RTEA350'}
for r in rows:
    sku = r.get('SKU','')
    if sku in TEA_SKUS:              r['Product'] = 'TEA'
    elif sku.endswith('350'):        r['Product'] = '350'
    elif sku.endswith('1') or sku.endswith('1L'): r['Product'] = '1L'
# Fix float quantities
for r in rows:
    try: r['Quantity'] = str(int(float(r['Quantity'])))
    except: pass
today = datetime.date.today().strftime('%d/%m/%Y')

by_order = defaultdict(list)
for r in rows:
    by_order[r['OrderNumber']].append(r)

def total_cartons(ords):
    # Sum ALL qty by product type first, THEN divide — mixed SKUs fill the same carton
    q350 = sum(int(r.get('Quantity',0) or 0) for r in ords if r.get('Product')=='350')
    qtea = sum(int(r.get('Quantity',0) or 0) for r in ords if r.get('Product')=='TEA')
    q1l  = sum(int(r.get('Quantity',0) or 0) for r in ords if r.get('Product')=='1L')
    t  = math.ceil(q350/24) if q350 else 0
    t += math.ceil(qtea/18) if qtea else 0
    t += math.ceil(q1l /12) if q1l  else 0
    return t

def inv_value(ords):
    return sum(float(r.get('UnitPrice',0) or 0)*int(r.get('Quantity',0) or 0) for r in ords if r.get('Product'))

def courier_orders(courier):
    return {k:v for k,v in by_order.items() if v[0].get('Courier','')==courier}

GREY = PatternFill('solid', fgColor='D3D3D3')
BOLD = Font(bold=True, name='Calibri', size=11)
generated = []

# ══════════════════════════════════════════════
# 1. COLDXPRESS
# ══════════════════════════════════════════════
if GEN_TYPE in ('coldxpress','all'):
    src = f'{TPL_DIR}/COLDXPRESS.xlsx'
    dst = f'{OUT_DIR}/{DATE_STR}_COLDXPRESS.xlsx'
    shutil.copy(src, dst)
    wb = load_workbook(dst)
    ws = wb.active
    ws['B4'] = today
    for ri in range(6, ws.max_row+1):
        for c in range(1, 16): ws.cell(ri,c).value = None
    cx = courier_orders('COLDXPRESS')
    for ri, onum in enumerate(sorted(cx.keys(), key=lambda o: cx[o][0].get('Customer','').upper()), 6):
        ords = cx[onum]; r0 = ords[0]
        ws.cell(ri,1).value = onum
        ws.cell(ri,2).value = r0.get('DeliveryDate','') or r0.get('DueDate','')
        ws.cell(ri,4).value = r0.get('Customer','')
        ws.cell(ri,5).value = r0.get('CustomerAddress1','')
        ws.cell(ri,6).value = r0.get('CustomerSuburb','')
        ws.cell(ri,7).value = r0.get('CustomerState','')
        try: ws.cell(ri,8).value = int(r0.get('Postcode',0))
        except: ws.cell(ri,8).value = r0.get('Postcode','')
        ws.cell(ri,9).value  = total_cartons(ords)
        ws.cell(ri,12).value = round(inv_value(ords),2)
        ws.cell(ri,14).value = 'chilled'
        ws.cell(ri,15).value = r0.get('Notes','')
    wb.save(dst); generated.append(dst)
    print(f'✅ COLDXPRESS — {len(cx)} orders', file=sys.stderr)

# ══════════════════════════════════════════════
# 2. DK DISTRIBUTIONS
# ══════════════════════════════════════════════
if GEN_TYPE in ('dk','all'):
    src = f'{TPL_DIR}/DK_DISTRIBUTIONS.xlsx'
    dst = f'{OUT_DIR}/{DATE_STR}_DK_DISTRIBUTIONS.xlsx'
    shutil.copy(src, dst)
    wb = load_workbook(dst)
    ws = wb['jobs']
    for ri in range(2, ws.max_row+1):
        for c in range(1, 19): ws.cell(ri,c).value = None
    dk = courier_orders('DKDISTRIBUTION')
    for ri, onum in enumerate(sorted(dk.keys(), key=lambda o: dk[o][0].get('Customer','').upper()), 2):
        ords = dk[onum]; r0 = ords[0]
        ws.cell(ri,1).value  = onum
        ws.cell(ri,2).value  = r0.get('DeliveryDate','') or r0.get('DueDate','')
        ws.cell(ri,3).value  = 'Business'
        ws.cell(ri,4).value  = r0.get('Customer','')
        ws.cell(ri,5).value  = r0.get('CustomerAddress1','')
        ws.cell(ri,6).value  = r0.get('CustomerAddress2','')
        try: ws.cell(ri,8).value = int(r0.get('Postcode',0))
        except: ws.cell(ri,8).value = r0.get('Postcode','')
        ws.cell(ri,9).value  = r0.get('CustomerSuburb','')
        ws.cell(ri,10).value = r0.get('CustomerState','')
        ws.cell(ri,15).value = r0.get('Notes','')
        ws.cell(ri,17).value = 'WS'
        ws.cell(ri,18).value = total_cartons(ords)
    wb.save(dst); generated.append(dst)
    print(f'✅ DK_DISTRIBUTIONS — {len(dk)} orders', file=sys.stderr)

# ══════════════════════════════════════════════
# 3. COOLCOURIERS
# ══════════════════════════════════════════════
if GEN_TYPE in ('coolcouriers','all'):
    src = f'{TPL_DIR}/COOLCOURIERS.xlsx'
    dst = f'{OUT_DIR}/{DATE_STR}_COOLCOURIERS.xlsx'
    shutil.copy(src, dst)
    wb = load_workbook(dst)
    ws = wb['jobs']
    for ri in range(2, ws.max_row+1):
        for c in range(1, 13): ws.cell(ri,c).value = None
    cc = courier_orders('COOLCOURIERS')
    for ri, onum in enumerate(sorted(cc.keys(), key=lambda o: cc[o][0].get('Customer','').upper()), 2):
        ords = cc[onum]; r0 = ords[0]
        ws.cell(ri,1).value  = onum
        ws.cell(ri,2).value  = r0.get('DeliveryDate','') or r0.get('DueDate','')
        ws.cell(ri,3).value  = 'Business'
        ws.cell(ri,4).value  = r0.get('Customer','')
        ws.cell(ri,5).value  = r0.get('CustomerAddress1','')
        ws.cell(ri,6).value  = r0.get('CustomerAddress2','')
        try: ws.cell(ri,7).value = int(r0.get('Postcode',0))
        except: ws.cell(ri,7).value = r0.get('Postcode','')
        ws.cell(ri,8).value  = r0.get('CustomerSuburb','')
        ws.cell(ri,9).value  = r0.get('CustomerState','')
        ws.cell(ri,10).value = r0.get('Notes','')
        ws.cell(ri,11).value = 'WS'
        ws.cell(ri,12).value = total_cartons(ords)
    wb.save(dst); generated.append(dst)
    print(f'✅ COOLCOURIERS — {len(cc)} orders', file=sys.stderr)

# ══════════════════════════════════════════════
# 4. PRODUCTION SHEET
# Uses insert_rows() to make space — handles any volume
# ══════════════════════════════════════════════
if GEN_TYPE in ('production','all'):
    src = f'{TPL_DIR}/Production_Sheet.xlsx'
    dst = f'{OUT_DIR}/{DATE_STR}_Production_Sheet.xlsx'
    shutil.copy(src, dst)
    wb = load_workbook(dst)
    ws = wb['Sheet1']

    # Update date row 1
    from datetime import date as _date
    d = _date.today()
    suffix = 'th' if 11<=d.day<=13 else {1:'st',2:'nd',3:'rd'}.get(d.day%10,'th')
    ws.cell(1,1).value = f"{d.strftime('%A')} - {d.day}{suffix} {d.strftime('%B %Y')}"

    # Build SKU lists dynamically from actual CSV data (sorted for consistent column order)
    SKUS_350 = sorted(set(r['Name'] for r in rows if r.get('Product') == '350'))
    SKUS_TEA = sorted(set(r['Name'] for r in rows if r.get('Product') == 'TEA'))
    SKUS_1L  = sorted(set(r['Name'] for r in rows if r.get('Product') == '1L'))

    def build_section_rows(skus, product_filter):
        """Build list of row dicts for this product section — couriers sorted, with subtotals + grand total."""
        couriers_data = defaultdict(list)
        for onum, ords in sorted(by_order.items(), key=lambda x: x[1][0].get('Customer','').upper()):
            pr = [r for r in ords if r.get('Product') == product_filter]
            if not pr: continue
            r0 = ords[0]
            sq = defaultdict(int)
            for r in pr: sq[r['Name']] += int(r.get('Quantity', 0) or 0)
            total_qty = sum(sq.values())
            divisor = 24 if product_filter=='350' else 18 if product_filter=='TEA' else 12
            tot_crt = total_qty / divisor  # exact decimal e.g. 2.5, not rounded up
            couriers_data[r0.get('Courier','')].append({
                'courier': r0.get('Courier',''), 'onum': onum,
                'cid': r0.get('CustomerId',''), 'cust': r0.get('Customer',''),
                'sq': dict(sq), 'tq': total_qty, 'tc': tot_crt
            })

        out_rows = []  # list of (is_subtotal, is_grandtotal, data_dict)
        grand_totals = defaultdict(int)
        grand_cartons = 0

        for courier in sorted(couriers_data.keys(), reverse=True):
            items = couriers_data[courier]
            cst = defaultdict(int); cqt = 0; cct = 0
            for it in items:
                out_rows.append(('data', it))
                for sku in skus: cst[sku] += it['sq'].get(sku, 0); grand_totals[sku] += it['sq'].get(sku, 0)
                cqt += it['tq']; cct += it['tc']; grand_cartons += it['tc']
            out_rows.append(('subtotal', {'courier': courier, 'cst': dict(cst), 'cqt': cqt, 'cct': cct}))

        out_rows.append(('grandtotal', {'grand_totals': dict(grand_totals), 'grand_cartons': grand_cartons}))
        return out_rows

    def write_section(ws, hrow, skus, product_filter):
        """
        Write section data with correct formatting:
        - Info boxes (LABELS/CUSTOMERGROUP/PRODUCT) removed including borders
        - Section title uppercase, size 14, bold
        - Batch Number box border spans col D to last data col
        - Header row: left-aligned A-D, centre-aligned SKU/total cols
        - Data rows: left-aligned A-D, centre-aligned quantities
        - Subtotal/GrandTotal: top+bottom border on ALL cols A through last_col
        """
        THIN      = Side(style='thin')
        NO_BORDER = Border()
        PLAIN     = Font(bold=False, name='Calibri', size=11)
        BOLD_F    = Font(bold=True,  name='Calibri', size=11)
        LEFT      = Alignment(horizontal='left')
        CENTER    = Alignment(horizontal='center')
        last_col  = 6 + len(skus)  # D=4, SKUs, Grand Total, Cartons

        # ── Remove info boxes (LABELS/CUSTOMERGROUP/PRODUCT) in cols O/P ──
        # They sit in the 3 rows before the Labelling Date row (hrow-3 to hrow-1 approx)
        for info_r in range(max(1, hrow - 6), hrow + 1):
            for info_c in range(last_col + 1, 20):
                cell = ws.cell(info_r, info_c)
                cell.value  = None
                cell.border = NO_BORDER

        # ── Section title: uppercase, bold, size 14 ──
        for title_r in range(max(1, hrow - 6), hrow):
            tv = ws.cell(title_r, 1).value
            if tv and isinstance(tv, str) and 'order' in tv.lower():
                ws.cell(title_r, 1).value = tv.upper()
                ws.cell(title_r, 1).font  = Font(bold=True, name='Calibri', size=14)

        # ── Batch Number box: outline border spanning col D to last_col ──
        batch_row = hrow - 1
        if batch_row >= 1 and ws.cell(batch_row, 4).value == 'Batch Number:':
            for bc in range(4, last_col + 1):
                ws.cell(batch_row, bc).border = Border(
                    top    = THIN,
                    bottom = THIN,
                    left   = THIN if bc == 4        else None,
                    right  = THIN if bc == last_col else None
                )

        # ── Header row: dynamic SKU names + alignment ──
        ws.cell(hrow, 1).value = 'Courier'
        ws.cell(hrow, 2).value = 'OrderNumber'
        ws.cell(hrow, 3).value = 'CustomerId'
        ws.cell(hrow, 4).value = 'Customer'
        for ci, sku in enumerate(skus, 5):
            ws.cell(hrow, ci).value = sku
        ws.cell(hrow, 5 + len(skus)).value = 'Grand Total'
        ws.cell(hrow, 6 + len(skus)).value = 'Cartons'
        for ci in range(last_col + 1, 20):
            ws.cell(hrow, ci).value  = None
            ws.cell(hrow, ci).border = NO_BORDER
        for ci in range(1, last_col + 1):
            ws.cell(hrow, ci).font      = BOLD_F
            ws.cell(hrow, ci).alignment = LEFT if ci <= 4 else CENTER

        # ── Find Discrepancies row ──
        disc_row = None
        for r in range(hrow + 1, ws.max_row + 2):
            if ws.cell(r, 1).value == 'Discrepancies:':
                disc_row = r; break
        if disc_row is None:
            print(f'  WARNING: no Discrepancies row found after row {hrow}', file=sys.stderr)
            return

        # ── Resize rows ──
        section_rows = build_section_rows(skus, product_filter)
        rows_needed  = len(section_rows)
        existing_data_rows = disc_row - hrow - 1
        print(f'  Section at row {hrow}: {existing_data_rows} existing rows, need {rows_needed}', file=sys.stderr)

        if rows_needed > existing_data_rows:
            insert_count = rows_needed - existing_data_rows
            ws.insert_rows(disc_row, insert_count)
            print(f'  Inserted {insert_count} rows before row {disc_row}', file=sys.stderr)
            disc_row += insert_count
        elif rows_needed < existing_data_rows:
            delete_count = existing_data_rows - rows_needed
            ws.delete_rows(hrow + 1, delete_count)
            print(f'  Deleted {delete_count} surplus rows', file=sys.stderr)
            disc_row -= delete_count

        # ── Write data rows ──
        for i, (rtype, rdata) in enumerate(section_rows):
            r = hrow + 1 + i
            # Clear entire row first
            for c in range(1, 20):
                ws.cell(r, c).value     = None
                ws.cell(r, c).font      = PLAIN
                ws.cell(r, c).border    = NO_BORDER
                ws.cell(r, c).alignment = Alignment()

            if rtype == 'data':
                for ci, val in enumerate([rdata['courier'], rdata['onum'], rdata['cid'], rdata['cust']], 1):
                    ws.cell(r, ci).value     = val
                    ws.cell(r, ci).alignment = LEFT
                for ci, sku in enumerate(skus, 5):
                    q = rdata['sq'].get(sku, 0)
                    if q:
                        ws.cell(r, ci).value     = q
                        ws.cell(r, ci).alignment = CENTER
                ws.cell(r, 5 + len(skus)).value     = rdata['tq']
                ws.cell(r, 5 + len(skus)).alignment = CENTER
                ws.cell(r, 6 + len(skus)).value     = rdata['tc']
                ws.cell(r, 6 + len(skus)).alignment = CENTER

            elif rtype in ('subtotal', 'grandtotal'):
                label = 'Total' if rtype == 'subtotal' else 'Grand Total'
                is_sub = rtype == 'subtotal'
                totals_by_sku = rdata['cst']        if is_sub else rdata['grand_totals']
                qty_total     = rdata['cqt']         if is_sub else sum(rdata['grand_totals'].values())
                cartons       = rdata['cct']         if is_sub else rdata['grand_cartons']

                # Border + bold across ALL cols A through last_col
                for c in range(1, last_col + 1):
                    ws.cell(r, c).font   = BOLD_F
                    ws.cell(r, c).border = Border(top=THIN, bottom=THIN)

                ws.cell(r, 4).value     = label
                ws.cell(r, 4).alignment = LEFT
                for ci, sku in enumerate(skus, 5):
                    v = totals_by_sku.get(sku, 0)
                    if v:
                        ws.cell(r, ci).value     = v
                        ws.cell(r, ci).alignment = CENTER
                ws.cell(r, 5 + len(skus)).value     = qty_total
                ws.cell(r, 5 + len(skus)).alignment = CENTER
                ws.cell(r, 6 + len(skus)).value     = cartons
                ws.cell(r, 6 + len(skus)).alignment = CENTER

    # Find section headers dynamically
    courier_rows = []
    for row in ws.iter_rows(min_row=1, max_row=ws.max_row):
        if row[0].value == 'Courier': courier_rows.append(row[0].row)

    r350_data = [r for r in rows if r.get('Product')=='350']
    rtea_data = [r for r in rows if r.get('Product')=='TEA']
    r1l_data  = [r for r in rows if r.get('Product')=='1L']

    if len(courier_rows) >= 3:
        # Write sections in REVERSE order so insert_rows doesn't shift subsequent section positions
        if r1l_data:  write_section(ws, courier_rows[2], SKUS_1L,  '1L')
        if rtea_data: write_section(ws, courier_rows[1], SKUS_TEA, 'TEA')
        write_section(ws, courier_rows[0], SKUS_350, '350')
    else:
        print(f'  ERROR: only found {len(courier_rows)} Courier header rows', file=sys.stderr)

    # Strip fill from all rows EXCEPT the 'Courier' header rows (SKU headers)
    NO_FILL = PatternFill(fill_type=None)
    for row in ws.iter_rows():
        is_header = row[0].value == 'Courier'
        if not is_header:
            for cell in row:
                cell.fill = NO_FILL

    # Delete Tea / 1L sections entirely if no orders for that SKU type
    def delete_section(ws, section_marker):
        start_row = None
        end_row = None
        for ri in range(1, ws.max_row + 1):
            v = str(ws.cell(ri, 1).value or '')
            if section_marker in v and start_row is None:
                start_row = ri
            if start_row and 'Discrepancies Sent to Sophie' in v:
                end_row = ri
                break
        if start_row and end_row:
            actual_start = start_row
            while actual_start > 1 and not ws.cell(actual_start - 1, 1).value:
                actual_start -= 1
            count = end_row - actual_start + 1
            ws.delete_rows(actual_start, count)
            print(f'  Deleted {section_marker} section ({count} rows)', file=sys.stderr)

    if not r1l_data:  delete_section(ws, '1L Orders')
    if not rtea_data: delete_section(ws, 'Tea Orders')

    wb.save(dst); generated.append(dst)
    print(f'✅ Production_Sheet', file=sys.stderr)

# ══════════════════════════════════════════════
# 5–9. PRINT FILES — built from scratch (no template needed)
#       Single sheet. All formula cols written explicitly.
#       FRONTS: order 1=blank, 2..N=data, N+1=blank; col F = CustomerId
#       BACKS:  order N+1=blank, N..2=data reversed, 1=blank; col F = BackLabels
# ══════════════════════════════════════════════
if GEN_TYPE in ('prints','all'):
    from openpyxl import Workbook
    from openpyxl.styles import Font as XFont, PatternFill as XFill

    XGREY = XFill('solid', fgColor='D3D3D3')
    XBOLD = XFont(bold=True, name='Calibri', size=11)
    HEADS = ['Order','#file','SKU','#copies','Customer','Customer ID','.PDF','CODE',
             '#pages','#papersize','#duplex','#orientation','#trayname']
    ADDR  = r'G:\\My Drive\\Print Files'

    def write_prow(ws, ri, order_n, sku, copies, customer, folder):
        ws.cell(ri,1).value = order_n
        # Col B: plain text computed path e.g. G:\\My Drive\\Print Files\\1073\\ANTIOX350.PDF
        ws.cell(ri,2).value = 'G:\\\\My Drive\\\\Print Files\\\\' + str(folder) + '\\\\' + sku + '.PDF'
        ws.cell(ri,3).value = sku
        ws.cell(ri,4).value = int(float(copies)) if copies else 24
        ws.cell(ri,5).value = customer if customer else None
        ws.cell(ri,6).value = folder
        ws.cell(ri,7).value = '.PDF'
        ws.cell(ri,8).value = sku + '.PDF'
        ws.cell(ri,9).value  = 'all'
        ws.cell(ri,10).value = 'As in printer'
        ws.cell(ri,11).value = 'As in printer'
        ws.cell(ri,12).value = 'Portrait'
        ws.cell(ri,13).value = 'As in printer'

    def make_print_file(sheet_name, is_backs, data, out_path, folder_override=None):
        wb = Workbook(); ws = wb.active; ws.title = sheet_name
        for ci, h in enumerate(HEADS, 1):
            c = ws.cell(1, ci, h); c.font = XBOLD; c.fill = XGREY
        total = len(data) + 2
        if not is_backs:
            write_prow(ws, 2, 1, 'BLANK', 24, None, 'BLANK')
            for i, r in enumerate(data, 3):
                write_prow(ws, i, i-1, r['SKU'], r['Quantity'], r['Customer'], folder_override if folder_override else r['CustomerId'])
            write_prow(ws, 2+len(data)+1, total, 'BLANK', 24, None, 'BLANK')
        else:
            # Entire data is reversed — rows printed in reverse so labels align on the backing roll
            reversed_data = list(reversed(data))
            write_prow(ws, 2, total, 'BLANK', 24, None, 'BLANK')
            for i, r in enumerate(reversed_data, 3):
                write_prow(ws, i, total-(i-2), r['SKU'], r['Quantity'], r['Customer'], r.get('BackLabels','BACKS') or 'BACKS')
            write_prow(ws, 2+len(data)+1, 1, 'BLANK', 24, None, 'BLANK')
        wb.save(out_path)
        generated.append(out_path)
        print(f'✅ {os.path.basename(out_path)} — {len(data)} lines, order 1–{total}', file=sys.stderr)

    # Courier Z→A (OTHER, DKDISTRIBUTION, COOLCOURIERS, COLDXPRESS), customer A→Z within each
    # Exclude SPECIAL customers — they use different label stock
    sr = sorted(rows, key=lambda r:([-ord(c) for c in r.get('Courier','').upper()], r.get('Customer','').upper(), r.get('OrderNumber',''), r.get('SKU','')))
    sr_regular = [r for r in sr if (r.get('Customergroup','') or '').strip().upper() != 'SPECIAL']
    r350=[r for r in sr_regular if r.get('Product')=='350']
    rtea=[r for r in sr_regular if r.get('Product')=='TEA']
    r1l =[r for r in sr_regular if r.get('Product')=='1L']

    make_print_file('FRONTS', False, r350, f'{OUT_DIR}/{DATE_STR}_350ml_Fronts.xlsx')
    make_print_file('BACKS',  True,  r350, f'{OUT_DIR}/{DATE_STR}_350ml_Backs.xlsx')
    if rtea: make_print_file('FRONTS', False, rtea, f'{OUT_DIR}/{DATE_STR}_Tea_Fronts.xlsx')
    if rtea: make_print_file('BACKS',  True,  rtea, f'{OUT_DIR}/{DATE_STR}_Tea_Backs.xlsx')
    if r1l:  make_print_file('FRONTS', False, r1l,  f'{OUT_DIR}/{DATE_STR}_1L_Fronts.xlsx', folder_override='1L')

    # ── SPECIAL customers: one fronts+backs pair per customer ──────
    import re as _re
    sr_special = [r for r in sr if (r.get('Customergroup','') or '').strip().upper() == 'SPECIAL']
    if sr_special:
        special_by_cid = {}
        for r in sr_special:
            cid = r.get('CustomerId','unknown')
            if cid not in special_by_cid:
                special_by_cid[cid] = {'name': r.get('Customer','Unknown'), 'rows': []}
            special_by_cid[cid]['rows'].append(r)
        for cid, cd in special_by_cid.items():
            safe = _re.sub(r'[^a-zA-Z0-9 ]', '', cd['name']).strip().replace(' ', '_')[:30]
            crows = cd['rows']
            c350 = [r for r in crows if r.get('Product') == '350']
            ctea = [r for r in crows if r.get('Product') == 'TEA']
            c1l  = [r for r in crows if r.get('Product') == '1L']
            if c350:
                make_print_file('FRONTS', False, c350, f'{OUT_DIR}/{safe}_350ml_Fronts.xlsx')
                make_print_file('BACKS',  True,  c350, f'{OUT_DIR}/{safe}_350ml_Backs.xlsx')
            if ctea:
                make_print_file('FRONTS', False, ctea, f'{OUT_DIR}/{safe}_Tea_Fronts.xlsx')
                make_print_file('BACKS',  True,  ctea, f'{OUT_DIR}/{safe}_Tea_Backs.xlsx')
            if c1l:
                make_print_file('FRONTS', False, c1l,  f'{OUT_DIR}/{safe}_1L_Fronts.xlsx', folder_override='1L')
        print(f'✅ SPECIAL prints — {len(special_by_cid)} customer(s)', file=sys.stderr)

# ══ ZIP all generated files ══
zip_path = f'{OUT_DIR}/{DATE_STR}_Wholesale_State_Files.zip'
with zipfile.ZipFile(zip_path, 'w', zipfile.ZIP_DEFLATED) as z:
    for fp in generated:
        z.write(fp, os.path.basename(fp))
print(f'✅ ZIP — {len(generated)} files', file=sys.stderr)

# ══ Output JSON to stdout (required by server) ══
result = {'paths': generated, 'files': [os.path.basename(p) for p in generated], 'zip': zip_path}
print(json.dumps(result))
`;

function validateCSV(rows) {
  const issues = [];
  const VALID_COURIERS = ['COLDXPRESS','DKDISTRIBUTION','COOLCOURIERS','WSDRIVER','RUN1','RUN2','RUN3'];
  const VALID_PRODUCTS = ['350','TEA','1L'];
  const TEA_SKUS = new Set(['LTEA350','PTEA350','RTEA350']);
  rows.forEach((r, i) => {
    const line = `Row ${i + 2} (${r.OrderNumber || '?'} — ${r.Customer || '?'})`;
    const sku = (r.SKU || '').trim();
    let product = r.Product;
    if (TEA_SKUS.has(sku))                             product = 'TEA';
    else if (sku.endsWith('350'))                       product = '350';
    else if (sku.endsWith('1') || sku.endsWith('1L'))   product = '1L';
    if (!product || !VALID_PRODUCTS.includes(product))
      issues.push(`${line}: SKU "${sku}" couldn't be classified as 350ml, Tea, or 1L`);
    if (!r.OrderNumber) issues.push(`${line}: Missing Order Number`);
    if (!r.Customer)    issues.push(`${line}: Missing Customer name`);
    if (!r.Courier || !VALID_COURIERS.includes((r.Courier || '').trim().toUpperCase()))
      issues.push(`${line}: Courier "${r.Courier || ''}" not recognised — must be COLDXPRESS, DKDISTRIBUTION, COOLCOURIERS, or WSDRIVER`);
    if (!r.Name) issues.push(`${line}: Missing product Name`);
    const qty = parseFloat(r.Quantity);
    if (isNaN(qty) || qty <= 0) issues.push(`${line}: Quantity "${r.Quantity}" is not valid`);
  });
  return issues;
}

app.post('/api/generate', auth, async (req, res) => {
  try {
    const { csvData, type, dateStr, force } = req.body;
    if (!csvData) return res.status(400).json({ error: 'No CSV data' });

    const tmpDir = '/tmp/ws_gen_' + Date.now();
    const outDir = '/tmp/ws_out_' + Date.now();
    await _mkdir(tmpDir, { recursive: true });
    await _mkdir(outDir, { recursive: true });

    const csvPath = tmpDir + '/orders.csv';
    const pyPath  = tmpDir + '/gen.py';
    const d = (dateStr || new Date().toLocaleDateString('en-AU')).replace(/\//g, '-');

    // csvData may be JSON array of row objects OR actual CSV text
    let csvText = csvData;
    let rowsForValidation = [];
    if (csvData.trim().startsWith('[')) {
      rowsForValidation = JSON.parse(csvData);
      if (rowsForValidation.length > 0) {
        const headers = Object.keys(rowsForValidation[0]);
        const esc = v => '"' + String(v == null ? '' : v).replace(/"/g, '""') + '"';
        csvText = [headers.join(','), ...rowsForValidation.map(r => headers.map(h => esc(r[h])).join(','))].join('\n');
      }
    }

    if (!force) {
      const validatableRows = rowsForValidation.filter(r => r.SKU !== 'FREIGHT');
      const issues = validateCSV(validatableRows);
      if (issues.length > 0) {
        return res.status(400).json({
          error: `Found ${issues.length} problem${issues.length > 1 ? 's' : ''} in your CSV — fix these before generating:`,
          issues
        });
      }
    }

    await _writeFile(csvPath, csvText);
    await _writeFile(pyPath, GEN_SCRIPT);

    const tplDir = existsSync(TPL_DIR) ? TPL_DIR : join(process.cwd(), 'public');
    const cmd = `python3 "${pyPath}" "${csvPath}" "${outDir}" "${d}" "${type}" "${tplDir}"`;
    const { stdout, stderr } = await execAsync(cmd, { timeout: 60000 });

    console.log('Generate log:', stderr.slice(0, 500));
    if (!stdout.trim()) throw new Error('Generator produced no output. ' + stderr.slice(0, 300));

    const result = JSON.parse(stdout.trim());

    if ((type === 'all' || type === 'prints') && result.zip) {
      const zipData = await _readFile(result.zip);
      const zipName = type === 'prints' ? `${d}_Print_Files.zip` : `${d}_Wholesale_State_Files.zip`;
      res.setHeader('Content-Type', 'application/zip');
      res.setHeader('Content-Disposition', `attachment; filename="${zipName}"`);
      return res.send(zipData);
    }
    if (result.paths && result.paths.length > 0) {
      const fileData = await _readFile(result.paths[0]);
      res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
      res.setHeader('Content-Disposition', `attachment; filename="${result.files[0]}"`);
      return res.send(fileData);
    }
    res.status(500).json({ error: 'No files generated', detail: stderr });
  } catch(e) {
    console.error('Generate error:', e.message);
    res.status(500).json({ error: e.message });
  }
});

app.post('/api/templates', auth, async (req, res) => {
  try {
    const { filename, data } = req.body;
    if (!filename || !data) return res.status(400).json({ error: 'Missing filename or data' });
    await _mkdir(TPL_DIR, { recursive: true });
    await _writeFile(join(TPL_DIR, filename), Buffer.from(data, 'base64'));
    res.json({ ok: true, filename });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

app.get('/api/templates', auth, async (req, res) => {
  try {
    const files = existsSync(TPL_DIR) ? await _readdir(TPL_DIR) : [];
    res.json({ files });
  } catch(e) { res.json({ files: [] }); }
});

// ── Distance Matrix proxy (avoids CORS) ─────────────────────────
app.post('/api/distance-matrix', auth, async (req, res) => {
  try {
    const { origins, destinations, departure_time } = req.body;
    if (!origins || !destinations) return res.status(400).json({ error: 'Missing origins or destinations' });

    const GMAPS_KEY = 'AIzaSyDdtmO12PIicsFNhbRGt-gJ_32MZHVl0Rk';
    const orig = origins.map(o => `${o.lat},${o.lon}`).join('|');
    const dest = destinations.map(d => `${d.lat},${d.lon}`).join('|');

    let url = `https://maps.googleapis.com/maps/api/distancematrix/json`
      + `?origins=${encodeURIComponent(orig)}`
      + `&destinations=${encodeURIComponent(dest)}`
      + `&mode=driving`
      + `&units=metric`
      + `&key=${GMAPS_KEY}`;

    // Add traffic-aware departure time if provided (seconds since epoch)
    if (departure_time) url += `&departure_time=${departure_time}&traffic_model=best_guess`;

    const fetch2 = fetch;
    const r = await fetch2(url);
    const data = await r.json();

    if (data.status !== 'OK') {
      return res.status(500).json({ error: data.status, detail: data.error_message });
    }

    res.json(data);
  } catch(e) {
    console.error('Distance matrix error:', e);
    res.status(500).json({ error: e.message });
  }
});

